// Generated by GitHub Copilot
import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { FiDollarSign, FiCreditCard, FiCheck, FiX } from 'react-icons/fi'
import PageHeader from '../../components/ui/PageHeader.jsx'
import Card, { CardBody, CardHeader } from '../../components/ui/Card.jsx'
import Badge from '../../components/ui/Badge.jsx'
import Button from '../../components/ui/Button.jsx'
import Select from '../../components/ui/Select.jsx'
import { memberLoanApi } from '../../api/memberLoanApi.js'
import { formatCurrency, formatDate } from '../../utils/format.js'
import Loader from '../../components/ui/Loader.jsx'

/** Member loans page with summary and history. */
export default function MemberLoans() {
  const navigate = useNavigate()
  const [loans, setLoans] = useState([])
  const [summary, setSummary] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  // Filters
  const [statusFilter, setStatusFilter] = useState('')
  const [currentPage, setCurrentPage] = useState(1)
  const [totalPages, setTotalPages] = useState(1)

  const fetchData = async () => {
    setLoading(true)
    setError('')
    
    try {
      // Fetch loans with filters
      const params = { page: currentPage, limit: 10 }
      if (statusFilter) params.status = statusFilter

      const loansRes = await memberLoanApi.getMyLoans(params)
      setLoans(loansRes.loans)
      setTotalPages(loansRes.pagination.totalPages)
    } catch (err) {
      setError(err.message || 'Failed to load loans')
    }
    
    try {
      // Fetch summary independently
      const summaryRes = await memberLoanApi.getMyLoanSummary()
      setSummary(summaryRes)
    } catch (err) {
      // Silently fail summary fetch - loans data is more important
      console.error('Failed to load loan summary:', err)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchData()
  }, [currentPage, statusFilter])


  const summaryCards = summary ? [
    {
      label: 'Total Borrowed',
      value: formatCurrency(summary.totalBorrowed),
      icon: FiDollarSign,
      tone: 'brand',
    },
    {
      label: 'Remaining Balance',
      value: formatCurrency(summary.totalRemaining),
      icon: FiCreditCard,
      tone: 'amber',
    },
    {
      label: 'Active Loans',
      value: summary.activeLoans.toString(),
      icon: FiCheck,
      tone: 'green',
    },
    {
      label: 'Closed Loans',
      value: summary.closedLoans.toString(),
      icon: FiX,
      tone: 'slate',
    },
  ] : []

  if (loading && !summary) {
    return (
      <div className="flex min-h-[60vh] items-center justify-center">
        <Loader label="Loading loans…" />
      </div>
    )
  }

  return (
    <div>
      <PageHeader
        title="My Loans"
        description="View your loan history and summary"
      />

      {error && (
        <div className="mb-4 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
          {error}
        </div>
      )}

      {/* Summary Cards */}
      {summary && (
        <div className="mb-6 grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4">
          {summaryCards.map((card) => {
            const Icon = card.icon
            return (
              <Card key={card.label}>
                <CardBody className="flex items-center gap-4">
                  <span className="flex h-12 w-12 items-center justify-center rounded-lg bg-slate-100 text-slate-600">
                    <Icon className="h-6 w-6" />
                  </span>
                  <div>
                    <p className="text-xs text-slate-500">{card.label}</p>
                    <p className="text-lg font-semibold text-slate-800">{card.value}</p>
                  </div>
                </CardBody>
              </Card>
            )
          })}
        </div>
      )}

      {/* Filters */}
      <Card className="mb-6">
        <CardBody>
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
            <Select
              label="Status"
              value={statusFilter}
              onChange={(e) => {
                setStatusFilter(e.target.value)
                setCurrentPage(1) // Reset to first page when filter changes
              }}
              options={[
                { value: '', label: 'All Status' },
                { value: 'active', label: 'Active' },
                { value: 'closed', label: 'Closed' },
              ]}
            />
            <div className="flex items-end">
              <Button
                variant="secondary"
                onClick={() => {
                  setStatusFilter('')
                  setCurrentPage(1) // Reset to first page when clearing filters
                }}
                className="w-full"
              >
                Clear Filters
              </Button>
            </div>
          </div>
        </CardBody>
      </Card>

      {/* Loans Table */}
      <Card>
        <CardHeader title="Loan History" subtitle={`Total: ${loans.length} records`} />
        <CardBody className="p-0">
          {loans.length === 0 ? (
            <div className="px-5 py-8 text-center">
              <p className="text-sm text-slate-500">No loans found</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="border-b border-slate-200 bg-slate-50">
                  <tr>
                    <th className="px-5 py-3 text-left font-semibold text-slate-700">Issue Date</th>
                    <th className="px-5 py-3 text-left font-semibold text-slate-700">Amount</th>
                    <th className="px-5 py-3 text-left font-semibold text-slate-700">Remaining</th>
                    <th className="px-5 py-3 text-left font-semibold text-slate-700">Due Date</th>
                    <th className="px-5 py-3 text-left font-semibold text-slate-700">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {loans.map((loan) => (
                    <tr key={loan.id} className="hover:bg-slate-50 cursor-pointer" onClick={() => navigate(`/member/loans/${loan.id}/passbook`)}>
                      <td className="px-5 py-4 font-medium text-slate-800">
                        {formatDate(loan.issueDate)}
                      </td>
                      <td className="px-5 py-4 text-slate-600">{formatCurrency(loan.amount)}</td>
                      <td className="px-5 py-4 text-slate-600">{formatCurrency(loan.remaining)}</td>
                      <td className="px-5 py-4 text-slate-600">
                        {formatDate(loan.dueDate)}
                      </td>
                      <td className="px-5 py-4">
                        <Badge variant={loan.status === 'active' ? 'success' : 'slate'}>
                          {loan.status}
                        </Badge>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardBody>
      </Card>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="mt-4 flex items-center justify-between">
          <Button
            variant="secondary"
            onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
            disabled={currentPage === 1}
          >
            Previous
          </Button>
          <span className="text-sm text-slate-600">
            Page {currentPage} of {totalPages}
          </span>
          <Button
            variant="secondary"
            onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
            disabled={currentPage === totalPages}
          >
            Next
          </Button>
        </div>
      )}
    </div>
  )
}